module current_sensor(  
    input wire clk,  
    input wire [3:0] current_in,  
    output reg obf_alarm_out  
);  
    parameter THRESHOLD = 9;  

    always @(posedge clk) begin  
        if (current_in > THRESHOLD)  
            obf_alarm_out <= 1'b1;  
        else  
            obf_alarm_out <= 1'b0;  
    end  
endmodule
